import React, { useState, useEffect } from "react";
import { Form, Button, Container } from "react-bootstrap";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import Header from "../../components/Headers/Header";

const EditDrug = () => {
    const { id } = useParams(); // Lấy id thuốc từ URL
    const navigate = useNavigate();

    const [drug, setDrug] = useState({
        medicine_code: "",
        medicine_name: "",
        medicine_type_name: "",
        price: "",
        unit: "",
        description: "",
    });

    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    // Lấy thông tin thuốc cần sửa
    useEffect(() => {
        fetchMedicine();
    }, []);

    const fetchMedicine = async () => {
        try {
            const response = await axios.get(`http://localhost:5001/api/medicine/${id}`);
            setDrug(response.data);
        } catch (error) {
            console.error("Lỗi khi lấy dữ liệu thuốc:", error);
            setError("Không tìm thấy thuốc hoặc có lỗi khi tải dữ liệu.");
        } finally {
            setLoading(false);
        }
    };

    // Xử lý thay đổi input
    const handleChange = (e) => {
        setDrug({ ...drug, [e.target.name]: e.target.value });
    };

    // Xử lý cập nhật thuốc
    const handleUpdate = async (e) => {
        e.preventDefault();
        try {
            await axios.put(`http://localhost:5001/api/medicine/${id}`, drug);
            alert("Cập nhật thành công!");
            navigate("/listOfDrugs"); // Điều hướng về danh sách thuốc
        } catch (error) {
            console.error("Lỗi khi cập nhật thuốc:", error);
            alert("Cập nhật thất bại!");
        }
    };

    if (loading) return <p>Đang tải dữ liệu...</p>;
    if (error) return <p style={{ color: "red" }}>{error}</p>;

    return (
        <>
            <Header />
            <Container className="mt-4">
                <h4>Chỉnh sửa thuốc</h4>
                <Form onSubmit={handleUpdate}>
                    <Form.Group controlId="medicine_code" className="mb-3">
                        <Form.Label>Mã thuốc</Form.Label>
                        <Form.Control
                            type="text"
                            name="medicine_code"
                            value={drug.medicine_code}
                            onChange={handleChange}
                            required
                        />
                    </Form.Group>

                    <Form.Group controlId="medicine_name" className="mb-3">
                        <Form.Label>Tên thuốc</Form.Label>
                        <Form.Control
                            type="text"
                            name="medicine_name"
                            value={drug.medicine_name}
                            onChange={handleChange}
                            required
                        />
                    </Form.Group>

                    <Form.Group controlId="medicine_type_name" className="mb-3">
                        <Form.Label>Loại thuốc</Form.Label>
                        <Form.Control
                            type="text"
                            name="medicine_type_name"
                            value={drug.medicine_type_name}
                            onChange={handleChange}
                        />
                    </Form.Group>

                    <Form.Group controlId="price" className="mb-3">
                        <Form.Label>Giá (VNĐ)</Form.Label>
                        <Form.Control
                            type="number"
                            name="price"
                            value={drug.price}
                            onChange={handleChange}
                            required
                        />
                    </Form.Group>

                    <Form.Group controlId="unit" className="mb-3">
                        <Form.Label>Đơn vị tính</Form.Label>
                        <Form.Control
                            type="text"
                            name="unit"
                            value={drug.unit}
                            onChange={handleChange}
                        />
                    </Form.Group>

                    <Form.Group controlId="description" className="mb-3">
                        <Form.Label>Mô tả</Form.Label>
                        <Form.Control
                            as="textarea"
                            rows={3}
                            name="description"
                            value={drug.description}
                            onChange={handleChange}
                        />
                    </Form.Group>

                    <Button variant="primary" type="submit">
                        Cập nhật
                    </Button>
                    <Button variant="secondary" className="ms-2" onClick={() => navigate("/listOfDrugs")}>
                        Hủy
                    </Button>
                </Form>
            </Container>
        </>
    );
};

export default EditDrug;
